import{_ as i,H as l,f as e,i as t}from"./chunks/framework.eFU6Tutu.js";const p=JSON.parse('{"title":"Инструкция по использованию ИИ ассистента","description":"","frontmatter":{},"headers":[],"relativePath":"AIintroduction.md","filePath":"AIintroduction.md"}'),r={name:"AIintroduction.md"};function o(n,a,d,h,s,c){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="инструкция-по-использованию-ии-ассистента" tabindex="-1">Инструкция по использованию ИИ ассистента <a class="header-anchor" href="#инструкция-по-использованию-ии-ассистента" aria-label="Permalink to &quot;Инструкция по использованию ИИ ассистента&quot;">​</a></h1><p>ИИ ассистент «Сада на подоконнике» помогает найти информацию о растениях, уходе и рецептах. Он отвечает только на основе статей и гайдов, размещённых на сайте.</p><h2 id="как-задавать-вопросы" tabindex="-1">Как задавать вопросы <a class="header-anchor" href="#как-задавать-вопросы" aria-label="Permalink to &quot;Как задавать вопросы&quot;">​</a></h2><p>Ассистент лучше всего отвечает на конкретные вопросы. Чем точнее вопрос, тем полезнее ответ.</p><p><strong>Примеры хороших вопросов:</strong></p><ul><li>Как часто поливать мяту?</li><li>Что приготовить из базилика?</li><li>Почему у спатифиллума желтеют листья?</li><li>Какой грунт нужен для помидоров на подоконнике?</li><li>Чем подкормить перец во время цветения?</li></ul><p><strong>Примеры не очень хороших вопросов:</strong></p><ul><li>Расскажи всё о растениях (слишком широко)</li><li>Помоги (непонятно, с чем именно)</li></ul><h2 id="как-ассистент-ищет-ответ" tabindex="-1">Как ассистент ищет ответ <a class="header-anchor" href="#как-ассистент-ищет-ответ" aria-label="Permalink to &quot;Как ассистент ищет ответ&quot;">​</a></h2><ol><li>Ассистент находит в базе знаний статьи, похожие по смыслу на ваш вопрос</li><li>Формулирует ответ только на основе этих статей</li><li>В конце ответа указывает источники — названия статей и гайдов</li></ol><p>Если точного ответа в базе нет, ассистент честно сообщит об этом.</p><h2 id="где-работает-ассистент" tabindex="-1">Где работает ассистент <a class="header-anchor" href="#где-работает-ассистент" aria-label="Permalink to &quot;Где работает ассистент&quot;">​</a></h2><p>Ассистент доступен на всех страницах сайта. Кнопка чата находится в правом нижнем углу экрана — зелёный кружок с иконкой сообщения.</p><p>Нажмите на кнопку, чтобы открыть окно чата, введите вопрос и получите ответ.</p><h2 id="важно" tabindex="-1">Важно <a class="header-anchor" href="#важно" aria-label="Permalink to &quot;Важно&quot;">​</a></h2><ul><li>Ассистент не отвечает на вопросы, не связанные с растениями, уходом и рецептами с этого сайта</li><li>Информация в ответах основана исключительно на статьях сайта</li></ul><h2 id="технические-требования" tabindex="-1">Технические требования <a class="header-anchor" href="#технические-требования" aria-label="Permalink to &quot;Технические требования&quot;">​</a></h2><p>Для работы ассистента необходимо:</p><ul><li>Современный браузер (Chrome, Firefox, Edge, Safari)</li><li>Включённый JavaScript</li></ul>',19)])])}const _=i(r,[["render",o]]);export{p as __pageData,_ as default};
